<script>
var QUESTIONS=[
{id:'q1',label:'Is your entity a Pvt Ltd, LLP, or registered Partnership Firm?',tip:'Sole proprietorships and HUFs are not eligible'},
{id:'q2',label:'Was the entity incorporated/registered less than 10 years ago?',tip:'Age from Certificate of Incorporation date'},
{id:'q3',label:'Is annual turnover below \u20B9100 Crore in every financial year?',tip:'Based on audited financial statements'},
{id:'q4',label:'Is the business working towards innovation or improvement of products/services?',tip:'Innovation, development, or significant improvement'},
{id:'q5',label:'Is it NOT formed by splitting or reconstruction of an existing business?',tip:'Must be an original new entity'},
{id:'q6',label:'Does the business have scalability potential for employment or wealth creation?',tip:'Should demonstrate growth potential'},
{id:'q7',label:'Is the entity NOT engaged purely in trading, real estate, or traditional business?',tip:'Pure trading without innovation does not qualify'}
];

function buildQuestions(){
var c=document.getElementById('eligItems');
QUESTIONS.forEach(function(q){
c.innerHTML+='<div class="elig-item" id="'+q.id+'"><div class="elig-label">'+q.label+'<div style="font-size:11px;color:var(--text-muted);margin-top:2px">'+q.tip+'</div></div><div class="elig-yn"><button class="y" onclick="setYN(\''+q.id+'\',this,true)">Yes</button><button class="n" onclick="setYN(\''+q.id+'\',this,false)">No</button></div></div>';
});
}

function setYN(id,btn,val){
var item=document.getElementById(id);
item.querySelectorAll('.elig-yn button').forEach(function(b){b.classList.remove('active');});
btn.classList.add('active');
item.classList.remove('pass','fail');
item.classList.add(val?'pass':'fail');
}

function getAnswers(){
var answers=[];
QUESTIONS.forEach(function(q){var item=document.getElementById(q.id);var a=item.querySelector('.elig-yn button.active');answers.push(a?a.classList.contains('y'):null);});
return answers;
}

function resetForm(){
QUESTIONS.forEach(function(q){var item=document.getElementById(q.id);item.classList.remove('pass','fail');item.querySelectorAll('.elig-yn button').forEach(function(b){b.classList.remove('active');});});
document.getElementById('resPanel').classList.remove('visible');
}

function checkElig(){
var answers=getAnswers();
var unanswered=answers.filter(function(a){return a===null;}).length;
if(unanswered>0){alert('Please answer all '+QUESTIONS.length+' questions.');return;}
var passed=answers.filter(function(a){return a===true;}).length;
var failed=answers.filter(function(a){return a===false;}).length;
var eligible=failed===0;
var pct=Math.round(passed/QUESTIONS.length*100);

var h='';
if(eligible){
h+='<div class="tool-hero"><div class="tool-box b1"><div class="tb-label">Eligibility</div><div class="tb-value">\u2714 Eligible</div><div class="tb-sub">DPIIT Recognition</div></div><div class="tool-box b2"><div class="tb-label">Score</div><div class="tb-value">'+passed+'/'+QUESTIONS.length+'</div><div class="tb-sub">All criteria met</div></div><div class="tool-box b3"><div class="tb-label">Tax Benefit</div><div class="tb-value">80-IAC</div><div class="tb-sub">3 years 100% exemption</div></div></div>';
h+='<div class="callout green"><p style="color:#166534"><strong>\u2714 Congratulations! Your business is eligible for Startup India DPIIT Recognition.</strong> Apply free at <a href="https://www.startupindia.gov.in/" target="_blank" rel="noopener">startupindia.gov.in</a>. Benefits include: Section 80-IAC tax exemption (3 years), angel tax exemption, patent fast-track (80% rebate), self-certification for labour laws, and Seed Fund access up to \u20B950L.</p></div>';
}else{
h+='<div class="tool-hero"><div class="tool-box" style="background:linear-gradient(135deg,#dc2626,#ef4444);color:#fff"><div class="tb-label">Eligibility</div><div class="tb-value">\u2718 Not Eligible</div><div class="tb-sub">'+failed+' criteria not met</div></div><div class="tool-box b2"><div class="tb-label">Score</div><div class="tb-value">'+passed+'/'+QUESTIONS.length+'</div><div class="tb-sub">'+pct+'% match</div></div><div class="tool-box b3"><div class="tb-label">Fix Required</div><div class="tb-value">'+failed+' items</div><div class="tb-sub">See details below</div></div></div>';
h+='<div class="callout" style="background:#FEF2F2;border-left-color:var(--danger)"><p style="color:#991B1B"><strong>\u2718 Not currently eligible.</strong> '+failed+' of '+QUESTIONS.length+' criteria are not met. Review the failed items below. Some issues like entity type can be resolved by incorporating as Pvt Ltd or LLP.</p></div>';
}

h+='<div class="res-card"><div class="res-card-hd"><h3>Criteria Assessment</h3><span class="res-badge '+(eligible?'pass':'fail')+'">'+(eligible?'Eligible':'Not Eligible')+'</span></div><div class="res-card-bd"><table class="cmp-table">';
QUESTIONS.forEach(function(q,i){
var pass=answers[i];
h+='<tr style="background:'+(pass?'#F0FDF4':'#FEF2F2')+'"><td>'+(pass?'\u2714':'\u2718')+' '+q.label+'</td><td style="color:'+(pass?'var(--success)':'var(--danger)')+';font-weight:700">'+(pass?'Yes':'No')+'</td></tr>';
});
h+='</table></div></div>';

h+='<div class="res-actions"><a href="https://wa.me/919459456700?text=Hi%2C%20I%20checked%20Startup%20India%20eligibility.%20I%20need%20help%20with%20DPIIT%20recognition." target="_blank" class="ra-btn"><svg viewBox="0 0 24 24" fill="#25D366" width="18" height="18"><path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347z"/></svg> Get DPIIT Help</a></div>';

document.getElementById('resBody').innerHTML=h;document.getElementById('resPanel').classList.add('visible');document.getElementById('resPanel').scrollIntoView({behavior:'smooth',block:'start'});
}

var FAQS=[
{q:"What is Startup India DPIIT recognition?",a:"DPIIT recognition under Startup India is official acknowledgement by the Department for Promotion of Industry and Internal Trade that a business qualifies as a startup. Recognition provides access to tax exemption under Section 80-IAC, self-certification for labour laws, fast-track patent processing, and funding through Fund of Funds."},
{q:"What are the eligibility criteria for Startup India?",a:"The entity must be incorporated as Pvt Ltd, LLP, or Partnership Firm. Age must be less than 10 years from incorporation. Annual turnover must not exceed 100 crore in any financial year. The business must work towards innovation, development, or improvement of products processes or services with potential for employment and wealth creation."},
{q:"What is the age limit for Startup India?",a:"The entity must be less than 10 years old from the date of incorporation or registration. For biotechnology startups the limit is also 10 years. Once the entity crosses 10 years it automatically loses startup status and associated benefits. Age is calculated from the date on the Certificate of Incorporation."},
{q:"What is the turnover limit for startup recognition?",a:"Annual turnover must not exceed 100 crore rupees in any financial year since incorporation. Turnover is calculated based on audited financial statements. If turnover exceeds 100 crore in any single year the entity loses its startup status from that year onwards. Previous year benefits are not affected."},
{q:"Can sole proprietorship get Startup India recognition?",a:"No. Only Private Limited Companies, LLPs, and registered Partnership Firms are eligible for DPIIT recognition under Startup India. Sole proprietorships and Hindu Undivided Families are not eligible. If you are a sole proprietor consider incorporating as a Pvt Ltd or LLP first before applying."},
{q:"What tax benefits do recognised startups get?",a:"Section 80-IAC provides 100 percent tax exemption on profits for 3 consecutive years out of the first 10 years from incorporation. Angel tax exemption under Section 56(2)(viib) for investments received above fair market value. Capital gains tax exemption under Section 54GB for investment in eligible startups."},
{q:"How to apply for Startup India recognition?",a:"Apply online at startupindia.gov.in. Create an account, fill the recognition form with entity details, upload Certificate of Incorporation and a brief description of business innovation. DPIIT processes applications within 2 to 5 working days. No fee is charged for recognition application."},
{q:"What documents are needed for DPIIT recognition?",a:"Certificate of Incorporation or Registration, a brief write-up of innovation or uniqueness of the business, and details of directors or partners. If applying for tax exemption under 80-IAC, an additional application to the Inter-Ministerial Board is required with audited financials and business plan."},
{q:"What is the Startup India Seed Fund Scheme?",a:"SEEDS provides financial assistance up to 50 lakh per startup through selected incubators across India. Grants up to 20 lakh for proof of concept and up to 50 lakh for product trials and market entry. The scheme targets early-stage startups that need capital for prototype development and commercialisation."},
{q:"Can existing businesses get Startup India recognition?",a:"Yes if the entity is less than 10 years old and turnover is below 100 crore. Existing businesses must demonstrate innovation or significant improvement in their products or services. Simply running a traditional business like a retail shop or restaurant without innovation does not qualify."},
{q:"What is the Fund of Funds for Startups?",a:"Government of India committed 10000 crore to Fund of Funds managed by SIDBI. The fund does not invest directly in startups but through SEBI registered Alternative Investment Funds that invest in startups. This has catalysed over 91000 crore in startup funding ecosystem as of 2025."},
{q:"How is innovation defined for Startup India?",a:"Innovation includes development of new products, services, or processes, or significant improvement of existing ones. It should be aimed at commercialisation and have scalability potential. Pure trading, real estate, and businesses derived from splitting of existing businesses are generally not considered innovative."},
{q:"Can a startup lose its DPIIT recognition?",a:"Yes recognition can be revoked if the entity crosses 10 years of age, turnover exceeds 100 crore, false information was provided in the application, or the entity ceases to work on innovation. DPIIT can also revoke recognition based on complaints or audit findings. The entity is given opportunity to respond before revocation."}
];
function buildFAQ(){var list=document.getElementById('faqList');FAQS.forEach(function(faq){var item=document.createElement('div');item.className='faq-item';item.innerHTML='<button class="faq-question" onclick="toggleFaq(this)"><span>'+faq.q+'</span><span class="faq-icon">+</span></button><div class="faq-answer"><div class="faq-answer-inner">'+faq.a+'</div></div>';list.appendChild(item);});}
function toggleFaq(btn){var item=btn.closest('.faq-item');var o=item.classList.contains('open');document.querySelectorAll('.faq-item').forEach(function(i){i.classList.remove('open');});if(!o)item.classList.add('open');}
var navLinks=document.querySelectorAll('.toc-nav a');window.addEventListener('scroll',function(){var cur='';document.querySelectorAll('[id]').forEach(function(s){if(pageYOffset>=s.offsetTop-80)cur=s.getAttribute('id');});navLinks.forEach(function(l){l.classList.toggle('active',l.getAttribute('href')==='#'+cur);});});
document.addEventListener('DOMContentLoaded',function(){buildFAQ();buildQuestions();});
</script>
